import json

def parse_tool_args(json_str):
    try:
        return json.loads(json_str), True
    except ValueError:
        return {}, False

def run_practice():
    args, ok = parse_tool_args('{"query": "Llama"}')
    assert ok
    assert args['query'] == 'Llama'
